content.text:
/* ============================================================
   Paul Simulator — Apex Dark + Amber Theme (Remodel v2)
   Bottom-tab mobile-first layout
   ============================================================ */

/* ---- Color Tokens ---- */
:root {
  --bg: #0d121b;
  --bg-surface: #0f141f;
  --bg-card: #131a27;
  --bg-hover: rgba(212, 167, 58, 0.05);
  --bg-active: rgba(212, 167, 58, 0.08);
  --bg-input: #0a0f18;
  --border: rgba(255, 255, 255, 0.06);
  --border-strong: rgba(255, 255, 255, 0.11);
  --border-gold: rgba(212, 167, 58, 0.3);
  --text: #c9d1d9;
  --text-bright: #f3f4f6;
  --text-muted: #6e7681;
  --text-dim: #424854;
  --gold: #d4a73a;
  --gold-dim: rgba(212, 167, 58, 0.4);
  --gold-bright: #fbbf24;
  --gold-bg: rgba(212, 167, 58, 0.08);
  --success: #86efac;
  --danger: #fca5a5;
  --warning: #fde047;
  --red: #EF4444;
  --red-dim: #B91C1C;
  --green: #10B981;
  --green-dim: #059669;
  --blue: #3B82F6;
  --purple: #8B5CF6;
  --font-display: 'Cinzel', serif;
  --font-mono: 'JetBrains Mono', monospace;
  --font-body: 'Inter', system-ui, sans-serif;
  --radius: 10px;
  --radius-lg: 14px;
  --ease: cubic-bezier(0.22, 1, 0.36, 1);
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --header-h: 44px;
  --tabs-h: 64px;
}

/* ---- Reset ---- */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

/* ---- Base ---- */
body {
  font-family: var(--font-mono);
  font-size: 13px;
  background: var(--bg);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
}

/* Grid texture background */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background-image:
    linear-gradient(rgba(255,255,255,0.024) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,0.024) 1px, transparent 1px);
  background-size: 48px 48px;
}

::selection { background: rgba(212,167,58,.25); color: #fff; }
.cinzel { font-family: var(--font-display); }

/* ---- Scrollbar ---- */
::-webkit-scrollbar { width: 4px; height: 4px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(212,167,58,0.15); border-radius: 4px; }
::-webkit-scrollbar-thumb:hover { background: rgba(212,167,58,0.3); }

/* ---- Utility ---- */
.hidden { display: none !important; }

/* ============================================================
   LOGIN SCREEN
   ============================================================ */
#login-screen {
  display: none;
  min-height: 100vh;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at center, #0f141f 0%, #0d121b 70%);
  position: relative;
  z-index: 1;
}
#login-screen.active { display: flex; }

.login-container {
  width: 100%;
  max-width: 400px;
  padding: 24px;
}

/* Onboarding hero */
.login-logo {
  text-align: center;
  margin-bottom: 40px;
}
.dragon-icon {
  font-size: 80px;
  margin-bottom: 16px;
  filter: drop-shadow(0 0 20px rgba(212,167,58,0.3));
}
.login-logo h1 {
  font-family: var(--font-display);
  font-size: 32px;
  color: var(--gold);
  letter-spacing: 3px;
  text-shadow: 0 0 30px rgba(212,167,58,0.2);
}
.login-logo .subtitle {
  font-size: 13px;
  color: var(--text-muted);
  margin-top: 8px;
  letter-spacing: 2px;
}

/* Login panels */
.login-panel { display: none; }
.login-panel.active { display: block; }

.login-divider {
  text-align: center;
  padding: 12px 0;
  color: var(--text-dim);
  font-size: 0.85rem;
}

/* ---- Forms ---- */
.form-group { margin-bottom: 1rem; }
.form-group label {
  display: block;
  font-size: 0.75rem;
  color: var(--text-muted);
  margin-bottom: 0.3rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

input[type="text"],
input[type="number"],
select,
textarea {
  width: 100%;
  padding: 10px 12px;
  background: var(--bg-input);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius);
  color: var(--text);
  font-size: 15px;
  font-family: inherit;
  transition: border-color 0.2s;
}
input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--gold);
  box-shadow: 0 0 0 2px rgba(212,167,58,0.15);
}
textarea { resize: vertical; min-height: 100px; }

.form-row {
  display: flex;
  gap: 10px;
  flex-wrap: wrap;
}
.form-row .form-group { flex: 1; min-width: 120px; }

/* ---- Buttons ---- */
.btn-gold {
  width: 100%;
  padding: 14px 20px;
  background: linear-gradient(180deg, rgba(212,167,58,0.18), rgba(212,167,58,0.08));
  border: 1px solid var(--gold-dim);
  color: var(--gold);
  border-radius: var(--radius);
  font-family: var(--font-mono);
  font-weight: 700;
  font-size: 15px;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
}
.btn-gold:hover {
  background: linear-gradient(180deg, rgba(212,167,58,0.25), rgba(212,167,58,0.12));
  box-shadow: 0 4px 15px rgba(212,167,58,0.15);
}

.btn-sm {
  padding: 6px 14px;
  font-size: 0.8rem;
  border-radius: var(--radius);
  border: 1px solid var(--border-strong);
  background: rgba(255,255,255,0.04);
  color: var(--text);
  cursor: pointer;
  font-family: inherit;
  transition: all 0.15s;
  white-space: nowrap;
}
.btn-sm:hover { background: var(--bg-hover); border-color: var(--gold-dim); color: var(--gold); }
.btn-sm.btn-gold { background: var(--gold-bg); border-color: var(--gold-dim); color: var(--gold); }
.btn-sm.btn-gold:hover { background: rgba(212,167,58,0.18); }

.btn-danger { background: rgba(239,68,68,0.1) !important; color: var(--red) !important; border-color: rgba(239,68,68,0.3) !important; }
.btn-danger:hover { background: rgba(239,68,68,0.2) !important; }
.btn-danger-sm { padding: 6px 12px; font-size: 0.8rem; border-radius: var(--radius); border: 1px solid rgba(239,68,68,0.3); background: rgba(239,68,68,0.08); color: var(--red); cursor: pointer; font-family: inherit; }

.btn-link {
  background: none;
  border: none;
  color: var(--text-muted);
  cursor: pointer;
  padding: 8px;
  font-size: 0.9rem;
  font-family: inherit;
  width: 100%;
  text-align: center;
}
.btn-link:hover { color: var(--gold); }
.btn-link strong { color: var(--text); }

.btn-lg { font-size: 1.05rem; padding: 16px 24px; }

.btn-obsidian { background: rgba(106,76,224,0.15) !important; color: #a78bfa !important; border: 1px solid rgba(106,76,224,0.4) !important; }
.btn-obsidian:hover { background: rgba(106,76,224,0.25) !important; }

.btn-ai-magic {
  background: linear-gradient(135deg, rgba(124,58,237,0.15), rgba(168,85,247,0.1)) !important;
  color: #c084fc !important;
  border: 1px solid rgba(168,85,247,0.3) !important;
  font-weight: 600;
}
.btn-ai-magic:hover { background: linear-gradient(135deg, rgba(124,58,237,0.25), rgba(168,85,247,0.15)) !important; box-shadow: 0 0 12px rgba(168,85,247,0.2); }

.btn-solo-adventure {
  display: block;
  width: 100%;
  padding: 10px;
  background: linear-gradient(135deg, rgba(124,58,237,0.12), rgba(168,85,247,0.06));
  border: 1px solid rgba(168,85,247,0.25);
  color: #c084fc;
  border-radius: var(--radius);
  font-family: inherit;
  font-size: 0.9rem;
  cursor: pointer;
  margin-bottom: 8px;
  text-align: center;
}

.btn-theme-toggle {
  padding: 6px 12px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text-muted);
  cursor: pointer;
  font-family: inherit;
  font-size: 0.85rem;
}

/* ---- Pin-related ---- */
.pin-hint { font-size: 0.85rem; margin-top: 4px; min-height: 1.2em; }
.dm-pin-display { display: flex; align-items: center; gap: 8px; justify-content: center; margin: 12px 0; }
.dm-pin-label { color: var(--text-muted); }
.dm-pin-value { font-family: monospace; font-size: 1.8rem; font-weight: 700; color: var(--gold); letter-spacing: 4px; }
.pin-save-warning { font-size: 0.85rem; color: #f4a236; text-align: center; margin: 8px 0; }
.add-player-row { display: flex; gap: 8px; margin-bottom: 12px; }
.add-player-row input { flex: 1; min-width: 0; }
.manage-players-section h3, .add-player-section h3, .player-roster h3 { color: var(--gold); margin-bottom: 8px; font-size: 0.95rem; }
.btn-copy-sm, .btn-regen-sm, .btn-remove-sm { background: none; border: none; cursor: pointer; font-size: 1rem; padding: 2px 4px; opacity: 0.7; transition: opacity 0.2s; }
.btn-copy-sm:hover, .btn-regen-sm:hover, .btn-remove-sm:hover { opacity: 1; }
.player-row { display: flex; align-items: center; gap: 8px; padding: 8px 10px; margin-bottom: 4px; background: rgba(255,255,255,0.03); border: 1px solid var(--border); border-radius: 6px; }
.player-row-name { flex: 1; font-weight: 600; }
.player-row-pin { font-family: monospace; font-size: 1.1rem; color: var(--gold); font-weight: 700; min-width: 50px; text-align: center; letter-spacing: 2px; }
.room-created-info { text-align: center; }
.room-created-info h2 { color: var(--gold); margin-bottom: 8px; }
.manage-players-container { max-width: 600px; }
.dm-pin-info-bar { display: flex; align-items: center; gap: 8px; padding: 10px; background: var(--gold-bg); border: 1px solid rgba(212,167,58,0.15); border-radius: var(--radius); margin-bottom: 16px; font-size: 0.9rem; }

.guide-link-container { margin-top: 16px; text-align: center; }
.guide-link { display: inline-block; color: var(--text-muted); font-size: 0.85rem; text-decoration: none; margin-top: 8px; }
.guide-link:hover { color: var(--gold); }

.error-msg { color: var(--red); text-align: center; margin-top: 10px; font-size: 0.85rem; }

/* ============================================================
   APP SCREEN — Bottom Tab Layout
   ============================================================ */
#app-screen {
  display: none;
  flex-direction: column;
  height: 100vh;
  position: relative;
  z-index: 1;
}
#app-screen.active { display: flex; }

/* ---- App Header ---- */
.app-header {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  height: var(--header-h);
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: center;
  padding: 0 16px;
  gap: 12px;
  font-size: 12px;
  z-index: 50;
}
.header-pin {
  font-family: monospace;
  color: var(--gold);
  font-weight: 700;
  font-size: 13px;
  letter-spacing: 1px;
}
.header-name { color: var(--text); font-weight: 600; }
.header-role { margin-left: auto; }
.role-badge {
  padding: 2px 8px;
  border-radius: 20px;
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}
.role-badge.dm { background: rgba(212,167,58,0.15); color: var(--gold); }
.role-badge.player { background: rgba(16,185,129,0.15); color: var(--green); }

.header-actions { display: flex; gap: 8px; margin-left: auto; align-items: center; }

/* Online players (compact in header) */
.header-players { display: flex; gap: 4px; align-items: center; }
.player-dot { display: inline-block; width: 8px; height: 8px; border-radius: 50%; }
.player-dot.dm { background: var(--gold); }
.player-dot.player { background: var(--green); }

/* ---- Bottom Tab Bar ---- */
.bottom-tabs {
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  height: var(--tabs-h);
  background: var(--bg-surface);
  border-top: 1px solid var(--border);
  display: flex;
  z-index: 50;
  padding-bottom: env(safe-area-inset-bottom, 0);
}
.tab-btn {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 2px;
  background: none;
  border: none;
  color: var(--text-dim);
  font-family: var(--font-mono);
  font-size: 10px;
  cursor: pointer;
  transition: color 0.15s;
  position: relative;
}
.tab-btn.active { color: var(--gold); }
.tab-btn:hover { color: var(--text-muted); }
.tab-icon { font-size: 22px; line-height: 1; }
.tab-label { font-weight: 500; }

/* ---- Tab Content Area ---- */
.tab-content-area {
  position: fixed;
  top: var(--header-h);
  bottom: var(--tabs-h);
  left: 0;
  right: 0;
  overflow: hidden;
  z-index: 1;
}
.tab-pane {
  display: none;
  height: 100%;
  overflow-y: auto;
  overflow-x: hidden;
}
.tab-pane.active { display: block; }

/* Placeholder styling */
.placeholder {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 200px;
  color: var(--text-dim);
  font-size: 14px;
  text-align: center;
}

/* ---- Panel Overlay (slide-in from right) ---- */
.panel-overlay {
  position: fixed;
  inset: 0;
  z-index: 100;
  background: var(--bg);
  transform: translateX(100%);
  transition: transform 0.3s var(--ease);
}
.panel-overlay.open { transform: translateX(0); }
.panel-header {
  height: var(--header-h);
  display: flex;
  align-items: center;
  padding: 0 12px;
  border-bottom: 1px solid var(--border);
  gap: 12px;
}
.panel-back {
  background: none;
  border: none;
  color: var(--gold);
  font-family: var(--font-mono);
  font-size: 13px;
  cursor: pointer;
}
.panel-title { font-weight: 600; color: var(--text-bright); }
.panel-body {
  height: calc(100% - var(--header-h));
  overflow-y: auto;
  padding: 16px;
}

/* ============================================================
   LEGACY TAB CONTENT (preserves old .tab-content system)
   The app.js switchTab() uses these selectors:
     $$('.tab-content') → toggle .active by id="tab-{name}"
   ============================================================ */
.tab-content { display: none; padding: 16px; }
.tab-content.active { display: block; }

/* Tab headers inside content */
.tab-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 10px;
  margin-bottom: 16px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--border);
}
.tab-header h1 {
  font-size: 1.3rem;
  color: var(--gold);
  letter-spacing: 1px;
}

/* ============================================================
   CARDS
   ============================================================ */
.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 16px;
}

/* ============================================================
   MODALS
   ============================================================ */
.modal {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 200;
  padding: 16px;
}
.modal.hidden { display: none; }
.modal-content {
  background: var(--bg-card);
  border: 1px solid var(--border-gold);
  border-radius: var(--radius-lg);
  padding: 24px;
  max-width: 450px;
  width: 100%;
  max-height: 85vh;
  overflow-y: auto;
}
.modal-content h3 { color: var(--gold); margin-bottom: 16px; }
.modal-lg { max-width: 620px; }
.modal-xl { max-width: 800px; }
.modal-actions { display: flex; gap: 8px; margin-top: 16px; flex-wrap: wrap; }
.modal-header-bar { display: flex; justify-content: space-between; align-items: center; margin-bottom: 16px; gap: 8px; }
.modal-header-bar div { display: flex; gap: 6px; flex-wrap: wrap; }

/* ============================================================
   TOAST NOTIFICATIONS
   ============================================================ */
.toast {
  position: fixed;
  bottom: calc(var(--tabs-h) + 16px);
  left: 50%;
  transform: translateX(-50%) translateY(100px);
  background: var(--bg-card);
  color: var(--text);
  padding: 12px 24px;
  border-radius: var(--radius);
  border: 1px solid var(--border-gold);
  z-index: 9999;
  transition: transform 0.3s ease, opacity 0.3s ease;
  opacity: 0;
  font-size: 0.9rem;
  max-width: 90vw;
  text-align: center;
  box-shadow: var(--shadow);
}
.toast.show { transform: translateX(-50%) translateY(0); opacity: 1; }
.toast-success { border-color: rgba(16,185,129,0.4); }
.toast-error { border-color: rgba(239,68,68,0.4); }

/* ============================================================
   ACHIEVEMENT TOAST
   ============================================================ */
.achievement-toast {
  position: fixed;
  bottom: calc(var(--tabs-h) + 16px);
  left: 50%;
  transform: translateX(-50%) translateY(100px);
  background: var(--bg-card);
  border: 1px solid var(--gold-dim);
  border-radius: var(--radius);
  padding: 12px 20px;
  z-index: 9999;
  display: flex;
  align-items: center;
  gap: 12px;
  opacity: 0;
  transition: transform 0.3s ease, opacity 0.3s ease;
  box-shadow: 0 0 30px rgba(212,167,58,0.15);
}
.achievement-toast.show { transform: translateX(-50%) translateY(0); opacity: 1; }
.toast-icon { font-size: 2rem; }
.toast-text { display: flex; flex-direction: column; gap: 2px; }
.toast-label { font-size: 0.7rem; color: var(--gold); text-transform: uppercase; letter-spacing: 1px; }
.toast-name { font-weight: 700; font-size: 1rem; }
.toast-player { font-size: 0.8rem; color: var(--text-muted); }

/* ============================================================
   LOOT SHARED NOTIFICATION
   ============================================================ */
.loot-shared-toast {
  position: fixed;
  bottom: calc(var(--tabs-h) + 16px);
  left: 50%;
  transform: translateX(-50%) translateY(100px);
  background: var(--bg-card);
  border: 1px solid var(--gold-dim);
  border-radius: var(--radius-lg);
  padding: 16px;
  z-index: 9999;
  opacity: 0;
  transition: transform 0.5s ease, opacity 0.5s ease;
  max-width: 90vw;
  box-shadow: 0 0 40px rgba(212,167,58,0.2);
}
.loot-shared-toast.show { transform: translateX(-50%) translateY(0); opacity: 1; }

/* ============================================================
   CHARACTER SHEET
   ============================================================ */
.char-sheet { position: relative; z-index: 1; }
.sheet-section { margin-bottom: 20px; padding: 16px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); }
.section-header { display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 8px; margin-bottom: 12px; }
.section-header h2 { font-size: 1rem; color: var(--gold); }
.sheet-section h2 { font-size: 1rem; color: var(--gold); margin-bottom: 10px; }

.char-actions { display: flex; gap: 8px; flex-wrap: wrap; align-items: center; }
.char-actions select { max-width: 200px; }

/* Ability scores */
.ability-scores-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(100px, 1fr)); gap: 10px; }
.ability-method { display: flex; align-items: center; gap: 8px; flex-wrap: wrap; }
.ability-method select { width: auto; max-width: 180px; }
.background-bonus { margin-top: 12px; }
.bonus-selector { display: flex; gap: 8px; align-items: center; flex-wrap: wrap; }
.bonus-selector select { width: auto; max-width: 150px; }
.bonus-selector label { font-size: 0.8rem; color: var(--text-muted); }

/* Combat stats */
.stat-boxes { display: grid; grid-template-columns: repeat(auto-fill, minmax(80px, 1fr)); gap: 8px; }
.stat-box { text-align: center; padding: 10px 6px; background: rgba(255,255,255,0.02); border: 1px solid var(--border); border-radius: var(--radius); }
.stat-label { font-size: 0.7rem; color: var(--text-muted); text-transform: uppercase; margin-bottom: 4px; }
.stat-value { font-size: 1.3rem; font-weight: 700; color: var(--text-bright); }
.hp-input { width: 60px; text-align: center; margin-top: 4px; padding: 4px; font-size: 0.9rem; }

/* Two column layout */
.two-col { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
@media (max-width: 600px) { .two-col { grid-template-columns: 1fr; } }

/* Notes */
.char-notes { min-height: 150px; width: 100%; }

/* Avatar */
.avatar-section { text-align: center; }
.avatar-upload-area { display: flex; flex-direction: column; align-items: center; gap: 8px; }
.avatar-display { width: 100px; height: 100px; border-radius: 50%; overflow: hidden; border: 2px solid var(--border-gold); display: flex; align-items: center; justify-content: center; cursor: pointer; background: var(--bg-surface); }
.avatar-display img { width: 100%; height: 100%; object-fit: cover; }
.avatar-placeholder { font-size: 3rem; }

/* ============================================================
   DICE ROLLER
   ============================================================ */
.dice-container { display: flex; flex-direction: column; gap: 16px; }
.dice-panel { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; }
.dice-quick { display: flex; gap: 8px; flex-wrap: wrap; justify-content: center; margin-bottom: 12px; }
.dice-btn {
  width: 52px; height: 52px;
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  gap: 2px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border-strong);
  border-radius: var(--radius);
  color: var(--text);
  cursor: pointer;
  font-family: inherit;
  font-size: 0.7rem;
  font-weight: 600;
  transition: all 0.15s;
}
.dice-btn:hover, .dice-btn.selected { border-color: var(--gold-dim); color: var(--gold); background: var(--gold-bg); }
.dice-btn.d20 { border-color: var(--gold-dim); }
.dice-shape { display: none; }
.dice-label { font-size: 0.75rem; }

.dice-multi-row { display: flex; gap: 6px; flex-wrap: wrap; align-items: center; margin-bottom: 10px; }
.dice-multi-label { font-size: 0.75rem; color: var(--text-muted); }
.dice-multi-btn {
  padding: 4px 10px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border);
  border-radius: 20px;
  color: var(--text-muted);
  font-family: inherit;
  font-size: 0.75rem;
  cursor: pointer;
}
.dice-multi-btn:hover { border-color: var(--gold-dim); color: var(--gold); }
.dice-special { border-color: rgba(168,85,247,0.2); color: #c084fc; }

.dice-modifier-row { display: flex; gap: 8px; align-items: center; margin-bottom: 10px; }
.modifier-label { font-size: 0.8rem; color: var(--text-muted); }
.dice-modifier-row select { width: auto; max-width: 80px; }

.dice-presets-section { margin-bottom: 10px; }
.dice-presets-label { font-size: 0.75rem; color: var(--text-muted); display: block; margin-bottom: 6px; }
.dice-presets-scroll { display: flex; gap: 6px; flex-wrap: wrap; }
.dice-preset-btn {
  padding: 5px 10px;
  background: rgba(255,255,255,0.03);
  border: 1px solid var(--border);
  border-radius: 20px;
  color: var(--text-muted);
  font-family: inherit;
  font-size: 0.75rem;
  cursor: pointer;
  white-space: nowrap;
}
.dice-preset-btn:hover { border-color: var(--gold-dim); color: var(--gold); }

.dice-custom { display: flex; flex-direction: column; gap: 8px; }

/* Dice tray */
.dice-tray { min-height: 100px; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 16px; background: var(--bg-surface); border-radius: var(--radius); margin-top: 12px; }
.dice-tray-dice { display: flex; gap: 8px; flex-wrap: wrap; justify-content: center; }
.tray-die {
  width: 48px; height: 48px;
  display: flex; align-items: center; justify-content: center;
  font-size: 1.2rem; font-weight: 700;
  border-radius: 8px;
  background: var(--bg-card);
  border: 2px solid var(--border-strong);
  color: var(--text-bright);
}
.tray-die.rolling { animation: dice-wobble 0.15s infinite; }
.tray-die.landed { animation: dice-land 0.3s ease-out; }
.tray-die.adv-kept { border-color: var(--gold); box-shadow: 0 0 8px rgba(212,167,58,0.3); }
.tray-die.adv-dropped { opacity: 0.4; text-decoration: line-through; }
.tray-die.dropped { opacity: 0.4; text-decoration: line-through; }
@keyframes dice-wobble { 0%,100% { transform: rotate(-5deg); } 50% { transform: rotate(5deg); } }
@keyframes dice-land { from { transform: scale(1.3); } to { transform: scale(1); } }

.dice-tray-result { text-align: center; margin-top: 12px; }
.result-total { font-size: 2.5rem; font-weight: 900; color: var(--text-bright); }
.result-total.crit-success { color: var(--gold-bright); text-shadow: 0 0 20px rgba(251,191,36,0.5); }
.result-total.crit-fail { color: var(--red); text-shadow: 0 0 20px rgba(239,68,68,0.5); }
.result-detail { font-size: 0.85rem; color: var(--text-muted); margin-top: 4px; }
.result-special { font-size: 1.2rem; font-weight: 700; margin-top: 6px; }
.result-special.critical { color: var(--gold-bright); }
.result-special.fumble { color: var(--red); }

/* Roll history */
.dice-history { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 12px; }
.dice-history h2 { font-size: 0.95rem; color: var(--gold); margin-bottom: 8px; }
.roll-log { max-height: 300px; overflow-y: auto; }
.roll-entry { display: flex; gap: 8px; align-items: center; padding: 4px 0; border-bottom: 1px solid rgba(255,255,255,0.03); font-size: 0.8rem; flex-wrap: wrap; }
.roll-time { color: var(--text-dim); font-size: 0.7rem; min-width: 60px; }
.roll-player { font-weight: 600; min-width: 60px; }
.roll-player.self { color: var(--gold); }
.roll-notation { color: var(--text-muted); }
.roll-result { font-weight: 700; color: var(--text-bright); }
.roll-detail { color: var(--text-dim); font-size: 0.75rem; }

/* ============================================================
   INITIATIVE TRACKER (styles injected by JS — supplement here)
   ============================================================ */
.initiative-list { display: flex; flex-direction: column; gap: 8px; }
.init-controls { display: flex; gap: 6px; flex-wrap: wrap; }

/* ============================================================
   SPELLS
   ============================================================ */
.spells-container { display: flex; flex-direction: column; gap: 12px; }
.spells-toolbar { display: flex; gap: 8px; flex-wrap: wrap; align-items: center; }
.spell-search { flex: 1; min-width: 180px; }
.spells-toolbar select { width: auto; max-width: 140px; }
.prepared-toggle { display: flex; align-items: center; gap: 6px; font-size: 0.8rem; color: var(--text-muted); cursor: pointer; }
.spells-layout { display: flex; flex-direction: column; gap: 12px; }
.spells-list { display: flex; flex-direction: column; gap: 6px; }
.spell-slot-tracker { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 12px; }
.spell-slot-tracker h3 { color: var(--gold); font-size: 0.9rem; margin-bottom: 8px; }
.slot-tracker-grid { display: flex; flex-direction: column; gap: 6px; }

/* ============================================================
   NPC / MONSTER
   ============================================================ */
.npc-toolbar, .monster-toolbar { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 12px; }
.npc-search, .monster-search { flex: 1; min-width: 150px; }
.npc-tag-filter { max-width: 180px; }
.npc-grid, .monster-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(260px, 1fr)); gap: 10px; }
.npc-header-actions, .monster-header-actions { display: flex; gap: 6px; flex-wrap: wrap; }

/* Stat block */
.stat-block { font-size: 0.85rem; line-height: 1.5; }
.stat-block-header h2 { color: var(--gold); font-family: var(--font-display); }
.stat-block-subtitle { color: var(--text-muted); font-style: italic; }
.stat-block-divider { height: 1px; background: var(--border-gold); margin: 8px 0; }
.stat-block-abilities { display: grid; grid-template-columns: repeat(6, 1fr); gap: 4px; text-align: center; margin: 8px 0; }
.stat-block-ability { padding: 4px; }
.ab-label { display: block; font-size: 0.7rem; color: var(--gold); font-weight: 700; }
.ab-val { display: block; font-size: 0.85rem; }
.stat-block-section-title { color: var(--gold); font-size: 0.9rem; margin: 8px 0 4px; border-bottom: 1px solid var(--border); padding-bottom: 4px; }
.stat-block-npc { border-left: 3px solid #f59e0b; padding-left: 12px; }
.stat-block-monster { border-left: 3px solid #ef4444; padding-left: 12px; }

/* ============================================================
   BATTLE MAP
   ============================================================ */
.map-container { display: flex; flex-direction: column; height: 100%; }
.map-toolbar { display: flex; justify-content: space-between; gap: 8px; flex-wrap: wrap; padding: 8px; background: var(--bg-surface); border-bottom: 1px solid var(--border); }
.map-toolbar-left, .map-toolbar-right { display: flex; gap: 4px; flex-wrap: wrap; align-items: center; }
.map-tool-btn {
  padding: 4px 8px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border);
  border-radius: 6px;
  color: var(--text-muted);
  font-family: inherit;
  font-size: 0.75rem;
  cursor: pointer;
  white-space: nowrap;
}
.map-tool-btn.active { border-color: var(--gold-dim); color: var(--gold); background: var(--gold-bg); }
.map-tool-btn:hover { border-color: var(--gold-dim); color: var(--gold); }
.map-upload-label { cursor: pointer; }
.map-grid-size-wrap { display: flex; align-items: center; gap: 4px; font-size: 0.75rem; color: var(--text-muted); }
.map-grid-size-wrap input[type="range"] { width: 60px; }

.map-body { display: flex; flex: 1; overflow: hidden; }
.map-token-sidebar { width: 220px; background: var(--bg-card); border-right: 1px solid var(--border); padding: 10px; overflow-y: auto; flex-shrink: 0; }
.map-token-sidebar.collapsed { width: 0; padding: 0; overflow: hidden; }
.token-sidebar-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 8px; }
.token-sidebar-header h3 { font-size: 0.9rem; color: var(--gold); }
.token-add-form { display: flex; flex-direction: column; gap: 4px; }
.token-add-form input, .token-add-form select { font-size: 0.8rem; padding: 4px 6px; }
.token-list-section h4 { font-size: 0.8rem; color: var(--text-muted); margin: 10px 0 6px; }
.map-token-list { display: flex; flex-direction: column; gap: 4px; }
.map-token-item { display: flex; align-items: center; gap: 6px; padding: 4px 6px; font-size: 0.8rem; background: rgba(255,255,255,0.02); border-radius: 4px; }
.token-color-dot { width: 10px; height: 10px; border-radius: 50%; flex-shrink: 0; }
.token-item-name { flex: 1; }
.token-item-size { font-size: 0.7rem; color: var(--text-dim); }
.token-remove-btn { background: none; border: none; color: var(--red); cursor: pointer; font-size: 0.8rem; }

.map-canvas-wrap { flex: 1; position: relative; overflow: hidden; cursor: grab; }
.map-canvas-wrap.dragging-token { cursor: grabbing; }
.map-canvas-wrap.measuring { cursor: crosshair; }
.map-canvas-wrap.fog-drawing { cursor: crosshair; }
.map-measure-label { position: absolute; background: rgba(0,0,0,0.8); color: var(--gold-bright); padding: 2px 8px; border-radius: 4px; font-size: 0.8rem; font-weight: 600; pointer-events: none; }

/* ============================================================
   NOTES / SESSION
   ============================================================ */
.notes-container { display: flex; flex-direction: column; gap: 16px; }
.notes-panel { display: flex; flex-direction: column; gap: 16px; }
.notes-editor h2, .notes-summaries h2, .notes-history h2, .notes-analytics h2, .notes-replay h2 { font-size: 1rem; color: var(--gold); margin-bottom: 8px; }
.notes-editor textarea { min-height: 200px; }
.notes-actions { display: flex; gap: 6px; flex-wrap: wrap; margin-top: 8px; }
.summaries-list { display: flex; flex-direction: column; gap: 8px; }
.session-history-list { display: flex; flex-direction: column; gap: 8px; max-height: 400px; overflow-y: auto; }
.session-history-content { max-height: 60vh; overflow-y: auto; padding: 8px; }

/* ============================================================
   WIKI
   ============================================================ */
.wiki-container { display: flex; gap: 16px; min-height: 400px; }
.wiki-sidebar { width: 280px; flex-shrink: 0; overflow-y: auto; border-right: 1px solid var(--border); padding-right: 12px; }
.wiki-search-bar { display: flex; flex-direction: column; gap: 6px; margin-bottom: 12px; }
.wiki-page-list { display: flex; flex-direction: column; gap: 4px; }
.wiki-category-section { margin-bottom: 12px; }
.wiki-category-header { font-size: 0.8rem; font-weight: 700; color: var(--gold); padding: 4px 0; margin-bottom: 4px; }
.wiki-page-item { display: flex; gap: 8px; padding: 8px; border-radius: 6px; cursor: pointer; transition: background 0.15s; }
.wiki-page-item:hover { background: var(--bg-hover); }
.wiki-page-item.active { background: var(--bg-active); border-left: 2px solid var(--gold); }
.wiki-page-icon { flex-shrink: 0; }
.wiki-page-info { flex: 1; min-width: 0; }
.wiki-page-title { font-weight: 600; font-size: 0.85rem; }
.wiki-page-preview { font-size: 0.75rem; color: var(--text-dim); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.wiki-page-draft { font-size: 0.65rem; color: var(--gold); background: var(--gold-bg); padding: 1px 6px; border-radius: 10px; }
.wiki-viewer { flex: 1; overflow-y: auto; }
.wiki-viewer-empty { text-align: center; padding: 60px 20px; color: var(--text-dim); }
.wiki-viewer-empty-icon { font-size: 3rem; margin-bottom: 12px; }
.wiki-viewer-header { display: flex; justify-content: space-between; align-items: flex-start; gap: 12px; margin-bottom: 16px; }
.wiki-viewer-header h2 { color: var(--gold); }
.wiki-view-meta { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 6px; }
.wiki-category-badge { font-size: 0.75rem; padding: 2px 8px; border-radius: 12px; background: var(--gold-bg); color: var(--gold); }
.wiki-tag { font-size: 0.7rem; padding: 2px 6px; border-radius: 10px; background: rgba(255,255,255,0.06); color: var(--text-muted); }
.wiki-view-body { line-height: 1.7; color: var(--text); }
.wiki-view-body h1, .wiki-view-body h2, .wiki-view-body h3, .wiki-view-body h4 { color: var(--gold); margin: 16px 0 8px; }
.wiki-view-body strong { color: var(--text-bright); }
.wiki-view-body code { background: rgba(255,255,255,0.06); padding: 2px 6px; border-radius: 4px; }
.wiki-view-body blockquote { border-left: 3px solid var(--gold-dim); padding-left: 12px; color: var(--text-muted); font-style: italic; }
.wiki-linked-list { display: flex; flex-wrap: wrap; gap: 6px; }
.wiki-linked-item { padding: 4px 10px; background: rgba(255,255,255,0.04); border: 1px solid var(--border); border-radius: 6px; cursor: pointer; font-size: 0.8rem; }
.wiki-linked-item:hover { border-color: var(--gold-dim); color: var(--gold); }
.wiki-edit-modal-content { max-width: 700px; }
.wiki-header-actions { display: flex; gap: 6px; }
.wiki-viewer-actions { display: flex; gap: 6px; }

@media (max-width: 700px) {
  .wiki-container { flex-direction: column; }
  .wiki-sidebar { width: 100%; border-right: none; border-bottom: 1px solid var(--border); padding-right: 0; padding-bottom: 12px; max-height: 200px; }
}

/* ============================================================
   CHAT
   ============================================================ */
.chat-container { display: flex; flex-direction: column; height: 100%; }
.chat-messages { flex: 1; overflow-y: auto; display: flex; flex-direction: column; gap: 6px; padding: 8px; }
.chat-empty { text-align: center; padding: 40px; color: var(--text-dim); }
.chat-input-bar { display: flex; gap: 8px; padding: 8px; border-top: 1px solid var(--border); background: var(--bg-surface); }
.chat-input-bar input { flex: 1; }
.chat-send-btn { width: auto; }
.chat-msg { max-width: 80%; padding: 8px 12px; border-radius: var(--radius); font-size: 0.85rem; }
.chat-msg-self { align-self: flex-end; background: rgba(212,167,58,0.1); border: 1px solid rgba(212,167,58,0.15); }
.chat-msg-dm { align-self: flex-start; background: rgba(212,167,58,0.06); border: 1px solid rgba(212,167,58,0.1); }
.chat-msg-player { align-self: flex-start; background: var(--bg-card); border: 1px solid var(--border); }
.chat-msg-system { align-self: center; text-align: center; color: var(--text-dim); font-size: 0.8rem; }
.chat-msg-header { display: flex; justify-content: space-between; gap: 8px; margin-bottom: 2px; }
.chat-msg-sender { font-weight: 700; font-size: 0.8rem; }
.chat-msg-time { font-size: 0.7rem; color: var(--text-dim); }
.chat-msg-text { line-height: 1.4; }
.chat-unread-badge { position: absolute; top: 2px; right: 8px; width: 16px; height: 16px; border-radius: 50%; background: var(--red); color: #fff; font-size: 0.6rem; display: flex; align-items: center; justify-content: center; font-weight: 700; }

/* ============================================================
   AI DUNGEON MASTER
   ============================================================ */
.ai-dm-char-select, .ai-dm-genre-select { padding: 20px; text-align: center; }
.ai-dm-genre-select h2 { color: var(--gold); margin-bottom: 16px; }
.ai-dm-genre-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(180px, 1fr)); gap: 10px; }
.ai-dm-genre-btn {
  display: flex; flex-direction: column; align-items: center; gap: 6px;
  padding: 16px; background: var(--bg-card); border: 1px solid var(--border-strong);
  border-radius: var(--radius); cursor: pointer; color: var(--text); font-family: inherit;
  transition: all 0.15s;
}
.ai-dm-genre-btn:hover { border-color: var(--gold-dim); background: var(--bg-hover); }
.genre-icon { font-size: 2rem; }
.genre-name { font-weight: 600; font-size: 0.9rem; }
.genre-desc { font-size: 0.75rem; color: var(--text-muted); }

.ai-dm-chat { display: flex; flex-direction: column; height: 100%; }
.ai-dm-chat-header { display: flex; justify-content: space-between; padding: 8px 12px; border-bottom: 1px solid var(--border); font-size: 0.8rem; }
.ai-dm-location { color: var(--gold); }
.ai-dm-msg-count { color: var(--text-dim); }
.ai-dm-messages { flex: 1; overflow-y: auto; padding: 12px; display: flex; flex-direction: column; gap: 12px; }
.ai-dm-msg { display: flex; gap: 10px; max-width: 90%; }
.ai-dm-msg-dm { align-self: flex-start; }
.ai-dm-msg-player { align-self: flex-end; flex-direction: row-reverse; }
.ai-dm-msg-system { align-self: center; }
.ai-dm-msg-avatar { font-size: 1.5rem; flex-shrink: 0; }
.ai-dm-msg-content { padding: 10px 14px; border-radius: var(--radius); line-height: 1.5; font-size: 0.85rem; }
.ai-dm-narrative { background: var(--bg-card); border: 1px solid var(--border); }
.ai-dm-player-msg { background: rgba(212,167,58,0.08); border: 1px solid rgba(212,167,58,0.15); }
.ai-dm-system-msg { background: rgba(255,255,255,0.03); color: var(--text-muted); font-size: 0.8rem; text-align: center; }
.ai-dm-typing .typing-dots { display: flex; gap: 4px; }
.ai-dm-typing .typing-dots span { width: 6px; height: 6px; background: var(--gold-dim); border-radius: 50%; animation: typing-bounce 0.6s infinite alternate; }
.ai-dm-typing .typing-dots span:nth-child(2) { animation-delay: 0.2s; }
.ai-dm-typing .typing-dots span:nth-child(3) { animation-delay: 0.4s; }
@keyframes typing-bounce { from { opacity: 0.3; } to { opacity: 1; transform: translateY(-2px); } }

.ai-dm-roll-prompt { padding: 12px; background: var(--bg-card); border: 1px solid var(--gold-dim); border-radius: var(--radius); display: flex; align-items: center; justify-content: space-between; gap: 12px; }
.ai-dm-roll-info { flex: 1; }
.ai-dm-roll-desc { display: block; font-weight: 600; }
.ai-dm-roll-dc { display: block; font-size: 0.8rem; color: var(--gold); }
.ai-dm-roll-btn { width: auto; }
.ai-dm-suggestions { display: flex; gap: 6px; flex-wrap: wrap; padding: 8px 12px; }
.ai-dm-suggestion-btn {
  padding: 6px 12px;
  background: rgba(255,255,255,0.04);
  border: 1px solid var(--border-strong);
  border-radius: 20px;
  color: var(--text);
  font-family: inherit;
  font-size: 0.8rem;
  cursor: pointer;
}
.ai-dm-suggestion-btn:hover { border-color: var(--gold-dim); color: var(--gold); }
.ai-dm-input-bar { display: flex; gap: 8px; padding: 8px 12px; border-top: 1px solid var(--border); background: var(--bg-surface); }
.ai-dm-input-bar input { flex: 1; }
.ai-dm-send-btn { width: auto; }
.ai-dm-char-preview { margin-top: 12px; }
.ai-dm-char-card { display: flex; flex-direction: column; gap: 2px; padding: 10px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); font-size: 0.85rem; }

/* ============================================================
   JOURNAL
   ============================================================ */
.journal-container { display: flex; flex-direction: column; gap: 12px; }
.journal-header-bar { display: flex; justify-content: space-between; align-items: center; gap: 8px; flex-wrap: wrap; }
.journal-char-label { font-weight: 600; color: var(--gold); }
.journal-actions { display: flex; gap: 6px; }
.journal-write-form { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; }
.journal-form-actions { display: flex; gap: 6px; margin-top: 8px; }
.journal-entries-list { display: flex; flex-direction: column; gap: 8px; }
.journal-empty { text-align: center; padding: 40px; color: var(--text-dim); }
.journal-entry-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 12px; }
.journal-entry-header { display: flex; justify-content: space-between; margin-bottom: 4px; }
.journal-entry-title { font-weight: 700; color: var(--text-bright); }
.journal-entry-date { font-size: 0.75rem; color: var(--text-dim); }
.journal-entry-session { font-size: 0.75rem; color: var(--gold); margin-bottom: 6px; display: block; }
.journal-entry-content { font-size: 0.85rem; color: var(--text); line-height: 1.5; white-space: pre-wrap; }

/* ============================================================
   ENCOUNTER BUILDER
   ============================================================ */
.encounter-layout { display: flex; gap: 16px; }
.encounter-builder-panel { flex: 1; }
.encounter-saved-panel { width: 280px; flex-shrink: 0; }
.encounter-builder, .encounter-simulator { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; }
.encounter-section { margin-top: 16px; }
.encounter-section h3 { font-size: 0.9rem; color: var(--gold); margin-bottom: 8px; }
.encounter-party-info { display: flex; flex-direction: column; gap: 4px; }
.encounter-party-card { padding: 6px 10px; background: rgba(255,255,255,0.03); border-radius: 6px; display: flex; justify-content: space-between; font-size: 0.8rem; }
.encounter-header-actions { display: flex; gap: 6px; }
.encounter-actions { display: flex; gap: 6px; flex-wrap: wrap; margin-top: 12px; }
.enc-monster-results { position: absolute; background: var(--bg-card); border: 1px solid var(--border-gold); border-radius: var(--radius); padding: 6px; max-height: 200px; overflow-y: auto; z-index: 10; width: 100%; }
.enc-monster-result-item { display: flex; justify-content: space-between; padding: 6px 8px; cursor: pointer; border-radius: 4px; }
.enc-monster-result-item:hover { background: var(--bg-hover); }
.encounter-monster-add { position: relative; margin-bottom: 8px; }
.encounter-monster-manual { margin-bottom: 8px; }
.enc-selected-monsters { display: flex; flex-direction: column; gap: 4px; }
.enc-monster-row { display: flex; align-items: center; gap: 8px; padding: 6px 8px; background: rgba(255,255,255,0.03); border-radius: 6px; font-size: 0.8rem; }
.enc-monster-row .em-info { flex: 1; }
.enc-monster-row .em-name { font-weight: 600; display: block; }
.enc-monster-row .em-stats { color: var(--text-dim); font-size: 0.75rem; }
.enc-monster-row .em-qty { display: flex; align-items: center; gap: 4px; }
.enc-monster-row .em-qty button { width: 24px; height: 24px; border: 1px solid var(--border); background: rgba(255,255,255,0.04); color: var(--text); border-radius: 4px; cursor: pointer; display: flex; align-items: center; justify-content: center; }
.enc-monster-row .em-remove { background: none; border: none; cursor: pointer; color: var(--red); }
.enc-difficulty-meter { margin-top: 8px; }
.enc-diff-bar-wrap { height: 12px; background: rgba(255,255,255,0.06); border-radius: 6px; overflow: hidden; position: relative; margin-bottom: 6px; }
.enc-diff-bar { height: 100%; background: linear-gradient(90deg, var(--green), var(--gold), #f97316, var(--red)); border-radius: 6px; transition: width 0.3s; }
.enc-diff-labels { display: flex; justify-content: space-between; font-size: 0.65rem; color: var(--text-dim); margin-top: 2px; }
.enc-diff-text { font-weight: 600; font-size: 0.85rem; }
.enc-diff-text.easy { color: var(--green); }
.enc-diff-text.medium { color: var(--gold); }
.enc-diff-text.hard { color: #f97316; }
.enc-diff-text.deadly { color: var(--red); }
.enc-diff-xp { font-size: 0.75rem; color: var(--text-muted); margin-top: 4px; }
.enc-diff-suggestion { font-size: 0.8rem; margin-top: 4px; color: var(--text-muted); }
.enc-ai-analysis { background: var(--bg-surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 12px; margin-top: 10px; font-size: 0.85rem; line-height: 1.5; white-space: pre-wrap; }
.enc-saved-list { display: flex; flex-direction: column; gap: 6px; }
.enc-saved-card { padding: 10px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); }
.enc-s-name { font-weight: 700; color: var(--text-bright); }
.enc-s-info { font-size: 0.75rem; color: var(--text-muted); margin: 4px 0; }
.enc-s-actions { display: flex; gap: 4px; }
.sim-result { background: var(--bg-surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 12px; margin-top: 8px; }

@media (max-width: 700px) {
  .encounter-layout { flex-direction: column; }
  .encounter-saved-panel { width: 100%; }
}

/* ============================================================
   RELATIONSHIPS
   ============================================================ */
.rel-container { display: flex; gap: 16px; min-height: 400px; }
.rel-graph-wrap { flex: 1; min-height: 300px; background: var(--bg-card); border-radius: var(--radius); overflow: hidden; }
.rel-graph-svg { width: 100%; height: 100%; }
.rel-sidebar { width: 260px; flex-shrink: 0; }
.rel-sidebar h3 { color: var(--gold); font-size: 0.9rem; margin-bottom: 8px; }
.rel-list { display: flex; flex-direction: column; gap: 4px; margin-bottom: 16px; }
.rel-item { display: flex; align-items: center; gap: 8px; padding: 6px 8px; background: rgba(255,255,255,0.03); border-radius: 6px; font-size: 0.8rem; }
.rel-names { flex: 1; }
.rel-type-badge { font-size: 0.7rem; padding: 2px 8px; border-radius: 10px; background: rgba(255,255,255,0.06); color: var(--text-muted); }
.rel-delete { background: none; border: none; cursor: pointer; color: var(--red); font-size: 0.8rem; }
.rel-legend { margin-top: 12px; }
.rel-legend h4 { font-size: 0.8rem; color: var(--text-muted); margin-bottom: 6px; }
.rel-legend-items { display: flex; flex-direction: column; gap: 4px; }
.rel-legend-item { display: flex; align-items: center; gap: 6px; font-size: 0.75rem; color: var(--text-muted); }
.rel-dot { width: 10px; height: 10px; border-radius: 50%; }
.rel-header-actions { display: flex; gap: 6px; }

@media (max-width: 700px) {
  .rel-container { flex-direction: column; }
  .rel-sidebar { width: 100%; }
}

/* ============================================================
   PLAYER STATS
   ============================================================ */
.stats-dashboard { display: flex; flex-direction: column; gap: 16px; }
.stats-section { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; }
.stats-section h3 { color: var(--gold); font-size: 0.95rem; margin-bottom: 10px; }
.stats-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(100px, 1fr)); gap: 8px; }
.stat-card { text-align: center; padding: 10px 6px; background: rgba(255,255,255,0.03); border-radius: var(--radius); }
.stat-card-value { font-size: 1.3rem; font-weight: 900; color: var(--text-bright); }
.stat-card.gold .stat-card-value { color: var(--gold); }
.stat-card.damage .stat-card-value { color: var(--red); }
.stat-card.healing .stat-card-value { color: var(--green); }
.stat-card-label { font-size: 0.7rem; color: var(--text-muted); margin-top: 2px; }
.stat-card-detail, .analytics-detail { font-size: 0.7rem; color: var(--text-dim); }
.stats-bar-chart { display: flex; flex-direction: column; gap: 4px; }
.stats-bar-row { display: flex; align-items: center; gap: 6px; }
.stats-bar-label { font-size: 0.7rem; color: var(--text-muted); min-width: 30px; }
.stats-bar-wrap { flex: 1; height: 8px; background: rgba(255,255,255,0.06); border-radius: 4px; overflow: hidden; }
.stats-bar-fill { height: 100%; border-radius: 4px; background: var(--gold); }
.stats-bar-value { font-size: 0.7rem; color: var(--text-dim); min-width: 40px; }
.d20-histogram { display: flex; align-items: flex-end; gap: 2px; height: 60px; }
.d20-hist-bar { flex: 1; background: var(--gold-dim); border-radius: 2px 2px 0 0; min-width: 4px; transition: height 0.3s; }
.d20-hist-labels { display: flex; justify-content: space-between; font-size: 0.55rem; color: var(--text-dim); }
.stats-empty { text-align: center; padding: 40px; color: var(--text-dim); }
.stats-progress { height: 6px; background: rgba(255,255,255,0.06); border-radius: 3px; overflow: hidden; margin-top: 4px; }
.stats-progress-fill { height: 100%; border-radius: 3px; background: var(--gold); }

/* Analytics */
.analytics-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(140px, 1fr)); gap: 8px; }
.analytics-card { text-align: center; padding: 12px 8px; background: rgba(255,255,255,0.03); border-radius: var(--radius); }
.analytics-value { font-size: 1.5rem; font-weight: 900; color: var(--gold); }
.analytics-label { font-size: 0.7rem; color: var(--text-muted); margin-top: 2px; }
.participation-chart { display: flex; flex-direction: column; gap: 4px; }
.participation-row { display: flex; align-items: center; gap: 6px; }
.participation-color { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }
.participation-name { font-size: 0.8rem; min-width: 80px; }
.participation-bar-wrap { flex: 1; height: 6px; background: rgba(255,255,255,0.06); border-radius: 3px; overflow: hidden; }
.participation-bar { height: 100%; border-radius: 3px; }
.participation-pct { font-size: 0.7rem; color: var(--text-dim); min-width: 30px; }

/* Replay */
.replay-controls { display: flex; gap: 6px; align-items: center; flex-wrap: wrap; margin-bottom: 8px; }
.replay-status { font-size: 0.8rem; color: var(--text-muted); }
.replay-event-log { max-height: 300px; overflow-y: auto; display: flex; flex-direction: column; gap: 2px; }
.replay-event { display: flex; gap: 8px; padding: 4px 8px; font-size: 0.8rem; border-radius: 4px; }
.replay-event.active { background: var(--gold-bg); }
.event-time { color: var(--text-dim); font-size: 0.7rem; min-width: 60px; }
.event-icon { flex-shrink: 0; }

/* ============================================================
   ACHIEVEMENT SYSTEM
   ============================================================ */
.achievement-gallery { display: grid; grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); gap: 8px; }
.achievement-badge { text-align: center; padding: 12px 8px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); }
.achievement-badge.locked { opacity: 0.3; filter: grayscale(1); }
.badge-icon { font-size: 2rem; display: block; margin-bottom: 4px; }
.badge-name { font-weight: 700; font-size: 0.8rem; color: var(--text-bright); display: block; }
.badge-desc { font-size: 0.7rem; color: var(--text-muted); display: block; margin-top: 2px; }

.badge-date { font-size: 0.65rem; color: var(--text-dim); display: block; margin-top: 2px; }

/* ============================================================
   COMPENDIUM
   ============================================================ */
.compendium-header-controls { display: flex; gap: 8px; align-items: center; }
.lang-toggle-btn { display: flex; align-items: center; gap: 4px; padding: 4px 10px; background: rgba(255,255,255,0.04); border: 1px solid var(--border); border-radius: var(--radius); color: var(--text-muted); cursor: pointer; font-family: inherit; font-size: 0.8rem; }
.lang-toggle-btn:hover { border-color: var(--gold-dim); color: var(--gold); }
.compendium-categories { display: flex; gap: 4px; flex-wrap: wrap; margin-bottom: 12px; }
.comp-cat-btn { padding: 6px 12px; background: rgba(255,255,255,0.04); border: 1px solid var(--border); border-radius: 20px; color: var(--text-muted); font-family: inherit; font-size: 0.8rem; cursor: pointer; }
.comp-cat-btn.active { background: var(--gold-bg); border-color: var(--gold-dim); color: var(--gold); }
.comp-cat-btn:hover { border-color: var(--gold-dim); color: var(--gold); }
.compendium-toolbar { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 10px; }
.compendium-search-input { flex: 1; min-width: 180px; }
.compendium-filters { display: flex; gap: 6px; flex-wrap: wrap; }
.compendium-filters select { width: auto; max-width: 160px; }
.compendium-results-info { font-size: 0.75rem; color: var(--text-dim); margin-bottom: 8px; }
.compendium-results { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 8px; }
.comp-card { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 12px; cursor: pointer; transition: all 0.15s; }
.comp-card:hover { border-color: var(--gold-dim); background: var(--bg-hover); }
.comp-card-header { display: flex; justify-content: space-between; align-items: center; gap: 8px; margin-bottom: 4px; }
.comp-card-name { font-weight: 700; font-size: 0.9rem; color: var(--text-bright); }
.comp-card-badge { font-size: 0.7rem; padding: 2px 8px; border-radius: 10px; background: var(--gold-bg); color: var(--gold); white-space: nowrap; }
.comp-card-meta { font-size: 0.75rem; color: var(--text-muted); margin-bottom: 4px; }
.comp-card-desc { font-size: 0.75rem; color: var(--text-dim); line-height: 1.4; overflow: hidden; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; }
.compendium-empty { text-align: center; padding: 40px; color: var(--text-dim); grid-column: 1 / -1; }
.empty-icon { font-size: 3rem; margin-bottom: 8px; }
.compendium-loading { text-align: center; padding: 40px; color: var(--text-muted); grid-column: 1 / -1; }
.comp-load-more { padding: 10px 20px; background: var(--bg-card); border: 1px solid var(--border-strong); border-radius: var(--radius); color: var(--text-muted); cursor: pointer; font-family: inherit; text-align: center; grid-column: 1 / -1; }
.comp-load-more:hover { border-color: var(--gold-dim); color: var(--gold); }

/* Compendium detail overlay */
.compendium-detail-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.7); z-index: 300; display: flex; align-items: center; justify-content: center; padding: 16px; }
.compendium-detail-overlay.hidden { display: none; }
.compendium-detail-modal { background: var(--bg-card); border: 1px solid var(--border-gold); border-radius: var(--radius-lg); padding: 24px; max-width: 700px; width: 100%; max-height: 85vh; overflow-y: auto; position: relative; }
.compendium-detail-close { position: absolute; top: 12px; right: 12px; background: rgba(255,255,255,0.06); border: 1px solid var(--border); border-radius: 6px; color: var(--text-muted); cursor: pointer; padding: 4px 10px; font-size: 1rem; }
.comp-detail-title { font-family: var(--font-display); font-size: 1.4rem; color: var(--gold); margin-bottom: 4px; padding-right: 40px; }
.comp-detail-subtitle { color: var(--text-muted); font-size: 0.85rem; margin-bottom: 16px; }
.comp-detail-section { margin-bottom: 16px; }
.comp-detail-section h3 { color: var(--gold); font-size: 0.9rem; margin-bottom: 8px; border-bottom: 1px solid var(--border); padding-bottom: 4px; }
.comp-desc-text { line-height: 1.7; color: var(--text); font-size: 0.85rem; }
.comp-desc-text p { margin-bottom: 8px; }
.comp-desc-text ul.feature-list { padding-left: 16px; margin: 8px 0; }
.comp-desc-text li { margin-bottom: 4px; }
.feature-subheading { color: var(--gold); display: block; margin-top: 10px; margin-bottom: 4px; }
.comp-detail-tags { display: flex; flex-wrap: wrap; gap: 4px; margin-top: 12px; }
.comp-detail-tag { font-size: 0.7rem; padding: 2px 8px; border-radius: 10px; background: rgba(255,255,255,0.06); color: var(--text-muted); }
.spell-detail-props { width: 100%; border-collapse: collapse; margin-bottom: 12px; }
.spell-detail-props dt { font-weight: 600; color: var(--text-muted); font-size: 0.8rem; }
.spell-detail-props dd { margin-left: 0; padding: 4px 0; border-bottom: 1px solid rgba(255,255,255,0.04); }
.spell-concentration-badge { display: inline-block; font-size: 0.65rem; padding: 2px 8px; border-radius: 10px; background: rgba(239,68,68,0.15); color: var(--red); margin-left: 8px; vertical-align: middle; }
.spell-ritual-badge { display: inline-block; font-size: 0.65rem; padding: 2px 8px; border-radius: 10px; background: rgba(59,130,246,0.15); color: var(--blue); margin-left: 4px; vertical-align: middle; }
.item-prop-badge { display: inline-block; font-size: 0.7rem; padding: 1px 6px; border-radius: 8px; background: rgba(255,255,255,0.06); margin-right: 4px; }

/* Class features collapsible */
.class-features-list { display: flex; flex-direction: column; gap: 4px; }
.class-feature-item { border: 1px solid var(--border); border-radius: 6px; overflow: hidden; cursor: pointer; }
.feature-header { display: flex; justify-content: space-between; padding: 8px 12px; background: rgba(255,255,255,0.02); }
.feature-name { font-weight: 600; font-size: 0.85rem; }
.feature-level { font-size: 0.75rem; color: var(--gold); }
.feature-body { display: none; padding: 8px 12px; font-size: 0.8rem; line-height: 1.5; border-top: 1px solid var(--border); }
.class-feature-item.expanded .feature-body { display: block; }
.subclass-group { border: 1px solid var(--border); border-radius: 6px; margin-bottom: 6px; }
.subclass-group-header { display: flex; justify-content: space-between; padding: 10px 12px; cursor: pointer; background: rgba(255,255,255,0.02); }
.subclass-group-header:hover { background: var(--bg-hover); }
.subclass-group-body { display: none; padding: 8px; }
.subclass-group.expanded .subclass-group-body { display: block; }

/* ============================================================
   RULEBOOK
   ============================================================ */
.rulebook-container { width: 100%; height: calc(100vh - var(--header-h) - var(--tabs-h) - 80px); min-height: 400px; }
.rulebook-iframe { width: 100%; height: 100%; border: none; border-radius: var(--radius); }

/* ============================================================
   ARENA
   ============================================================ */
.arena-setup { padding: 16px; }
.arena-setup-columns { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; }
@media (max-width: 600px) { .arena-setup-columns { grid-template-columns: 1fr; } }
.arena-setup-panel { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; }
.arena-setup-panel h2 { font-size: 1rem; color: var(--gold); margin-bottom: 12px; }
.arena-entity-list { display: flex; flex-direction: column; gap: 6px; }
.arena-entity-card { display: flex; align-items: center; gap: 8px; padding: 8px 10px; background: rgba(255,255,255,0.03); border: 1px solid var(--border); border-radius: var(--radius); cursor: pointer; transition: all 0.15s; }
.arena-entity-card.selected { border-color: var(--gold-dim); background: var(--gold-bg); }
.arena-entity-card:hover { border-color: var(--gold-dim); }
.entity-icon { font-size: 1.3rem; flex-shrink: 0; }
.entity-info { flex: 1; }
.entity-name { font-weight: 600; font-size: 0.85rem; }
.entity-meta { font-size: 0.7rem; color: var(--text-muted); }
.entity-stats { font-size: 0.75rem; color: var(--text-dim); display: flex; gap: 8px; }
.entity-qty { display: flex; align-items: center; gap: 4px; }
.entity-qty button { width: 24px; height: 24px; border: 1px solid var(--border); background: rgba(255,255,255,0.04); color: var(--text); border-radius: 4px; cursor: pointer; display: flex; align-items: center; justify-content: center; }
.arena-start-wrap { text-align: center; margin-top: 16px; }
.arena-start-wrap .btn-lg { width: auto; display: inline-flex; padding: 14px 40px; }
.arena-monster-search-wrap { position: relative; margin-bottom: 8px; }
.arena-monster-results { position: absolute; background: var(--bg-card); border: 1px solid var(--border-gold); border-radius: var(--radius); padding: 4px; max-height: 180px; overflow-y: auto; z-index: 10; width: 100%; }
.arena-monster-result-item { display: flex; justify-content: space-between; padding: 6px 8px; cursor: pointer; border-radius: 4px; font-size: 0.85rem; }
.arena-monster-result-item:hover { background: var(--bg-hover); }

.arena-combat { display: flex; flex-direction: column; gap: 12px; padding: 12px; }
.arena-battlefield { display: grid; grid-template-columns: 1fr auto 1fr; gap: 12px; align-items: start; }
.arena-vs { text-align: center; color: var(--gold); font-weight: 700; font-size: 0.85rem; padding-top: 20px; }
.arena-monsters-side, .arena-party-side { display: flex; flex-direction: column; gap: 6px; }
.arena-combatant { display: flex; flex-direction: column; align-items: center; gap: 2px; padding: 8px; background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); text-align: center; position: relative; min-width: 80px; transition: all 0.2s; }
.arena-combatant.active-combatant { border-color: var(--gold); box-shadow: 0 0 12px rgba(212,167,58,0.2); }
.arena-combatant.dead { opacity: 0.3; filter: grayscale(0.8); }
.arena-combatant.defending { border-color: var(--blue); }
.combatant-init { position: absolute; top: 2px; right: 4px; font-size: 0.6rem; color: var(--text-dim); }
.combatant-icon { font-size: 1.5rem; }
.combatant-name { font-weight: 600; font-size: 0.75rem; }
.combatant-class { font-size: 0.65rem; color: var(--text-dim); }
.combatant-hp-bar { width: 100%; height: 4px; background: rgba(255,255,255,0.1); border-radius: 2px; overflow: hidden; margin-top: 2px; }
.combatant-hp-fill { height: 100%; border-radius: 2px; transition: width 0.3s; }
.combatant-hp-text { font-size: 0.7rem; }
.combatant-ac { font-size: 0.65rem; color: var(--text-muted); }
.arena-turn-bar { text-align: center; padding: 10px; background: var(--bg-surface); border-radius: var(--radius); }
.arena-turn-name { font-weight: 700; font-size: 1rem; color: var(--gold); margin-bottom: 8px; }
.arena-action-buttons { display: flex; gap: 6px; justify-content: center; flex-wrap: wrap; }
.arena-action-btn { padding: 8px 16px; background: var(--bg-card); border: 1px solid var(--border-strong); border-radius: var(--radius); color: var(--text); font-family: inherit; font-size: 0.85rem; cursor: pointer; }
.arena-action-btn:hover:not(:disabled) { border-color: var(--gold-dim); color: var(--gold); }
.arena-action-btn:disabled { opacity: 0.4; cursor: default; }
.arena-target-select, .arena-spell-select { position: fixed; inset: 0; background: rgba(0,0,0,0.8); z-index: 150; display: flex; flex-direction: column; align-items: center; justify-content: center; gap: 10px; padding: 20px; }
.arena-target-list, .arena-spell-list { display: flex; flex-direction: column; gap: 6px; width: 100%; max-width: 400px; }
.arena-target-btn, .arena-spell-btn { padding: 10px 16px; background: var(--bg-card); border: 1px solid var(--border-strong); border-radius: var(--radius); color: var(--text); font-family: inherit; cursor: pointer; text-align: left; }
.arena-target-btn:hover, .arena-spell-btn:hover { border-color: var(--gold-dim); background: var(--bg-hover); }
.target-hp { display: block; font-size: 0.75rem; color: var(--text-muted); margin-top: 2px; }
.arena-log-wrap { background: var(--bg-card); border: 1px solid var(--border); border-radius: var(--radius); padding: 10px; max-height: 200px; overflow-y: auto; }
.arena-log-wrap h3 { font-size: 0.85rem; color: var(--gold); margin-bottom: 6px; }
.arena-combat-log { font-size: 0.75rem; line-height: 1.4; }
.arena-log-entry { padding: 2px 0; }
.arena-log-entry.log-system { color: var(--text-muted); }
.arena-log-entry.log-attack { color: var(--text); }
.arena-log-entry.log-hit { color: var(--green); }
.arena-log-entry.log-miss { color: var(--text-dim); }
.arena-log-entry.log-damage { color: var(--red); }
.arena-log-entry.log-crit { color: var(--gold-bright); font-weight: 700; }
.arena-log-entry.log-death { color: var(--red); font-weight: 700; }
.arena-log-entry.log-heal { color: var(--green); }
.arena-log-entry.log-defend { color: var(--blue); }
.arena-log-entry.log-flee { color: var(--purple); }
.arena-log-entry.log-spell { color: #c084fc; }

.arena-float-number { position: absolute; pointer-events: none; font-weight: 900; font-size: 1.2rem; animation: float-up 1.5s ease-out forwards; z-index: 10; }
.arena-float-number.damage { color: var(--red); }
.arena-float-number.crit { color: var(--gold-bright); font-size: 1.5rem; }
.arena-float-number.heal { color: var(--green); }
.arena-float-number.miss { color: var(--text-dim); font-size: 0.9rem; }
@keyframes float-up { 0% { opacity: 1; transform: translateY(0); } 100% { opacity: 0; transform: translateY(-40px); } }
.arena-shake { animation: shake 0.3s; }
@keyframes shake { 0%,100% { transform: translateX(0); } 25% { transform: translateX(-3px); } 75% { transform: translateX(3px); } }
.arena-flash { animation: flash 0.3s; }
@keyframes flash { 0% { filter: brightness(2); } 100% { filter: brightness(1); } }

.arena-result { text-align: center; padding: 40px 20px; }
.arena-result-victory h2 { color: var(--gold); font-size: 2rem; margin-bottom: 16px; }
.arena-result-defeat h2 { color: var(--red); font-size: 2rem; margin-bottom: 16px; }
.result-stats { font-size: 0.9rem; line-height: 1.8; }
.result-stats p { margin: 4px 0; }
.loot-section { margin-top: 12px; padding-top: 12px; border-top: 1px solid var(--border); }
.arena-header-actions { display: flex; gap: 6px; }

/* ============================================================
   LOOT GENERATOR
   ============================================================ */
.loot-generator-section { margin-top: 24px; border-top: 1px solid var(--border); padding-top: 16px; }
.loot-gen-header h2 { color: var(--gold); margin-bottom: 10px; }
.loot-gen-controls { margin-bottom: 12px; }
.treasure-chest-card { background: var(--bg-card); border: 1px solid var(--border-gold); border-radius: var(--radius-lg); padding: 16px; }
.treasure-chest-header { display: flex; align-items: center; gap: 10px; margin-bottom: 12px; }
.chest-icon { font-size: 2rem; }
.treasure-chest-header h3 { color: var(--gold); }
.loot-currency { display: flex; gap: 10px; flex-wrap: wrap; margin-bottom: 10px; }
.loot-coin { display: flex; align-items: center; gap: 4px; padding: 4px 10px; background: rgba(255,255,255,0.04); border-radius: 20px; font-size: 0.85rem; font-weight: 600; }
.coin-icon { font-size: 0.9rem; }
.loot-items-list { display: flex; flex-direction: column; gap: 4px; }
.loot-item { display: flex; align-items: center; gap: 8px; padding: 6px 10px; background: rgba(255,255,255,0.03); border-radius: 6px; }
.loot-item-icon { font-size: 1.2rem; flex-shrink: 0; }
.loot-item-name { font-weight: 600; }
.loot-item-rarity { font-size: 0.7rem; padding: 2px 8px; border-radius: 10px; white-space: nowrap; }
.rarity-common { background: rgba(255,255,255,0.06); color: var(--text-muted); }
.rarity-uncommon { background: rgba(16,185,129,0.15); color: var(--green); }
.rarity-rare { background: rgba(59,130,246,0.15); color: var(--blue); }
.rarity-very-rare { background: rgba(139,92,246,0.15); color: var(--purple); }
.rarity-legendary { background: rgba(212,167,58,0.15); color: var(--gold); }
.loot-actions { margin-top: 10px; }
.loot-share-btn { padding: 8px 16px; background: var(--gold-bg); border: 1px solid var(--gold-dim); border-radius: var(--radius); color: var(--gold); cursor: pointer; font-family: inherit; font-size: 0.85rem; }

/* ============================================================
   RULES LAWYER FAB
   ============================================================ */
.rules-lawyer-fab {
  position: fixed;
  bottom: calc(var(--tabs-h) + 16px);
  right: 16px;
  z-index: 40;
  padding: 8px 16px;
  background: var(--bg-card);
  border: 1px solid var(--border-gold);
  border-radius: 20px;
  color: var(--gold);
  font-family: inherit;
  font-size: 0.8rem;
  cursor: pointer;
  box-shadow: var(--shadow);
}
.rules-lawyer-fab:hover { background: var(--bg-hover); }

.rules-modal .rules-quick-buttons { display: flex; gap: 4px; flex-wrap: wrap; margin-bottom: 12px; }
.rules-quick-btn { padding: 4px 10px; background: rgba(255,255,255,0.04); border: 1px solid var(--border); border-radius: 20px; color: var(--text-muted); cursor: pointer; font-family: inherit; font-size: 0.75rem; }
.rules-quick-btn:hover { border-color: var(--gold-dim); color: var(--gold); }
.rules-answer-card { background: var(--bg-surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; line-height: 1.6; font-size: 0.85rem; white-space: pre-wrap; }
.rules-recent { margin-top: 12px; }
.rules-recent h4 { font-size: 0.85rem; color: var(--gold); margin-bottom: 6px; }
.rules-recent-item { padding: 4px 8px; cursor: pointer; border-radius: 4px; font-size: 0.8rem; color: var(--text-muted); }
.rules-recent-item:hover { background: var(--bg-hover); color: var(--text); }

/* ============================================================
   AI STATUS
   ============================================================ */
.ai-status { padding: 10px; border-radius: var(--radius); margin: 10px 0; font-size: 0.9rem; background: rgba(168,85,247,0.1); border: 1px solid rgba(168,85,247,0.3); color: #c084fc; }
.ai-error { background: rgba(244,67,54,0.1) !important; border: 1px solid rgba(244,67,54,0.3) !important; color: #f44336 !important; }

/* ============================================================
   QUEST/TRAP GENERATOR
   ============================================================ */
.quest-gen-modal, .trap-gen-modal { max-width: 700px !important; }
.quest-result-card, .trap-result-card { background: var(--bg-surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 16px; margin-top: 12px; line-height: 1.6; }
.quest-result-card h2, .trap-result-card h2 { color: var(--gold); margin-bottom: 8px; }
.quest-result-card h3, .trap-result-card h3 { color: var(--gold); font-size: 0.95rem; margin: 12px 0 6px; }
.quest-result-card ul, .trap-result-card ul { padding-left: 16px; }
.quest-result-card li, .trap-result-card li { margin-bottom: 4px; }
.quest-actions, .trap-actions { display: flex; gap: 6px; margin-top: 10px; }

/* ============================================================
   CONDITION PILLS (initiative tracker enhanced)
   ============================================================ */
.condition-pill {
  display: inline-block;
  padding: 2px 8px;
  border-radius: 12px;
  font-size: 0.7rem;
  cursor: pointer;
  border: 1px solid;
  border-color: var(--pill-color, var(--text-dim));
  color: var(--pill-color, var(--text-dim));
  background: rgba(255,255,255,0.03);
  margin: 1px;
}
.condition-pill:hover { background: rgba(255,255,255,0.08); }
.condition-expiring { animation: pulse-warn 1s infinite; }
@keyframes pulse-warn { 0%,100% { opacity: 1; } 50% { opacity: 0.5; } }
.condition-concentration { border-style: dashed; }
.init-conditions-enhanced { display: flex; flex-wrap: wrap; gap: 2px; margin-top: 4px; }
.enhanced-condition-select { background: var(--bg-input); color: var(--text); border: 1px solid var(--border); border-radius: 4px; padding: 2px 4px; font-size: 0.75rem; font-family: inherit; }
.condition-duration-input { display: flex; gap: 4px; align-items: center; margin-top: 4px; }
.condition-duration-input input, .condition-duration-input select { font-size: 0.75rem; padding: 2px 4px; }
.condition-add-confirm { padding: 2px 8px; }

/* ============================================================
   MUTED / MISC
   ============================================================ */
.muted { color: var(--text-dim); }
.screen { display: none; }
.screen.active { display: flex; }

/* ============================================================
   LIGHT THEME OVERRIDE
   ============================================================ */
[data-theme="light"] {
  --bg: #f5f5f5;
  --bg-surface: #ffffff;
  --bg-card: #ffffff;
  --bg-input: #f0f0f0;
  --border: rgba(0,0,0,0.08);
  --border-strong: rgba(0,0,0,0.15);
  --border-gold: rgba(180,140,40,0.3);
  --text: #1a1a1a;
  --text-bright: #000000;
  --text-muted: #666666;
  --text-dim: #999999;
  --gold: #9a7b2a;
  --gold-dim: rgba(154,123,42,0.4);
  --gold-bright: #b8922e;
  --gold-bg: rgba(154,123,42,0.08);
}

/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (max-width: 480px) {
  .tab-header { flex-direction: column; align-items: flex-start; }
  .tab-header h1 { font-size: 1.1rem; }
  .char-actions { width: 100%; }
  .char-actions select { max-width: 100%; width: 100%; }
  .stat-boxes { grid-template-columns: repeat(3, 1fr); }
  .ability-scores-grid { grid-template-columns: repeat(3, 1fr); }
  .arena-battlefield { grid-template-columns: 1fr; }
  .arena-vs { padding: 8px 0; }
}

/* ---- Hidden nav-btn elements (old sidebar buttons, hidden but kept for JS) ---- */
.nav-btn { display: none !important; }

/* ---- Hidden old sidebar elements ---- */
#sidebar, #sidebar-overlay, #mobile-header { display: none !important; }
.apex-sidebar, .apex-hamburger { display: none !important; }

/* More tab feature buttons */
.more-card-btn {
  display: flex; flex-direction: column; align-items: center; justify-content: center;
  gap: 4px; padding: 20px 12px; background: var(--bg-card, #131a27);
  border: 1px solid var(--border, rgba(255,255,255,0.06)); border-radius: 10px;
  color: var(--text, #c9d1d9); font-family: var(--font-mono, 'JetBrains Mono', monospace);
  font-size: 13px; font-weight: 500; cursor: pointer; transition: all 0.15s;
  min-height: 64px;
}
.more-card-btn:hover {
  border-color: rgba(212,167,58,0.4); background: rgba(212,167,58,0.06);
  color: #d4a73a;
}
.more-card-btn:active { transform: scale(0.97); }

/* Make sure legacy tab-content displays properly in new layout */
.tab-content { display: none; padding: 16px; overflow-y: auto; }
.tab-content-area { position: relative; z-index: 1; }

